var e=e=>{console.log(`%c[Analytics] ${e.eventName.toUpperCase()}`,`color: #ffd053; background: #640c0e; padding: 2px 6px; border-radius: 4px; font-weight: bold;`,e)},t={trackLessonCompletion(t,n,r){e({eventName:`lesson_completed`,courseId:t,lessonId:n,lessonTitle:r,timestamp:new Date().toISOString()})},trackQuizAttempt(t,n,r,i){e({eventName:`quiz_attempted`,courseId:t,quizId:n,score:r,passed:i,timestamp:new Date().toISOString()})},trackCourseCompletion(t,n){e({eventName:`course_completed`,courseId:t,courseTitle:n,timestamp:new Date().toISOString()})},trackCertificateAward(t,n){e({eventName:`certificate_awarded`,courseId:t,certificateCode:n,timestamp:new Date().toISOString()})},trackStudentEngagement(t){e({eventName:`engagement_tracked`,engagementType:t,timestamp:new Date().toISOString()})}};export{t};